var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"시체의 피가 전부 사라졌어.","JPN":"死体の血が全部消えてる。","ENG":"The corpse is completely drained of blood.","TWN":"屍體的血全都消失了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"죽은 지 오래된 시체는 아닌 것 같은데…….","JPN":"死んでからあまり時間は経ってなさそうだが……","ENG":"Doesn't seem like it's been dead for long...","TWN":"看起來不是死了很久的屍體……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"형제님?","JPN":"ブラザー？","ENG":"Brother Ludwig?","TWN":"弟兄？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……끊어졌군.","JPN":"……切れてる。","ENG":"...The connection's cut off.","TWN":"……掛斷了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"젠장. 지금이라도 돌아갈까?","JPN":"くそ。今からでも帰るか？","ENG":"Damn it. Should I turn back now?","TWN":"可惡。要不現在回去？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만, 이 시체는 그냥 넘어갈 수 없겠는데.","JPN":"でも、死体をこのまま放っておけないしな。","ENG":"But I can't just ignore this body.","TWN":"但是，這具屍體不能輕易忽略。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"합의체의 키메라? 챔버가 합의체의 연구를 도와준다는 소문은 들었는데.","JPN":"合意体のキメラ？　チェンバーが合意体の研究を援助しているって噂は聞いたけど。","ENG":"A chimera from the Northern Union? I've heard rumors that Chamber was helping with their research.","TWN":"和議會的奇美拉？聽說和議會的研究得到了強巴的幫助。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그렇다고 해도…… 왜 그게 대부호의 저택에 있냐고.","JPN":"そうだとしても……どうしてそれが大富豪の邸宅にいるわけ？","ENG":"But even if that's true... why is it in a noble's mansion?","TWN":"即便如此……為什麼那會在大富翁的屋子裡呢。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"필요할때만 날 찾는구나.","JPN":"必要な時しか呼んでくれないのね。","ENG":"You only call me when you need something.","TWN":"你只有在需要的時候才會找我。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"내가 그렇게 버릇없게 키운 적은 없었던 것 같은데.","JPN":"私、そんなに礼儀知らずな子に育てた覚えはないけれど。","ENG":"Pretty sure I didn't raise you to be so rude.","TWN":"我好像從來沒有把你教得這麼沒規矩。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"키우긴 뭘 키워요. 사진이나 엄청나게 찍어댔지.","JPN":"育ててないでしょう。写真を撮りまくってただけじゃないですか。","ENG":"Raise me? More like spent all your time taking pictures of me.","TWN":"教什麼教，只是拍了很多照片而已。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"여기서 한 번 <color=#ffd34c>광증</color>이 발현됐어요.","JPN":"それはそうと、さっき<color=#ffd34c>狂症</color>が発現しました。","ENG":"There was a case of the <color=#ffd34c>madness</color> here.","TWN":"在這裡，我的<color=#ffd34c>狂症</color>發作了一次。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"광증? 네가?","JPN":"狂症？　あなたが？","ENG":"Madness? Are you talking about yourself?","TWN":"狂症？你？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"어쩌면 만월이라 그럴 가능성도 있겠어.","JPN":"満月だからって可能性もあるわね。","ENG":"Maybe it's because of the full moon... That would make sense.","TWN":"也許是因為月圓的緣故吧。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만…… 좀 예민해지기만 할 뿐 이런 적은 없었는데.","JPN":"でも……今まではちょっと敏感になるだけだったのに。","ENG":"But... it usually just makes you a little on edge. You've never lost control like this before.","TWN":"但是……只是變得有些敏感而已，之前從未有過這樣的情況。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"갑자기 이러니까 좀 이상하더라고요.","JPN":"いきなりああなるなんて、ちょっとおかしいです。","ENG":"Yeah. It felt strange.","TWN":"突然這樣做，有點奇怪呢。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>10년 전 그날</color>에도 멀쩡했던 제가…….","JPN":"<color=#ffd34c>10年前のあの日</color>にも何ともなかった私が……","ENG":"Even <color=#ffd34c>ten years ago</color> on that night, I stayed completely sane.","TWN":"<color=#ffd34c>10年前的那天</color>我也安然無恙。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"순식간에 이성을 잃었다는게.","JPN":"一瞬で理性を失うなんて。","ENG":"But now, all of a sudden, I snap?","TWN":"瞬間就失去了理智。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"다시 그런 증상이 나타나기 전에 서두르자.","JPN":"またその症状が出る前に急ぎましょう。","ENG":"Let's wrap this up before it happens again.","TWN":"在再次出現那種症狀之前趕緊行動吧。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"수녀는 찾았어?","JPN":"シスターは見つかった？","ENG":"Did you find the nun?","TWN":"找到修女了嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L42_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"여기에도 수녀는 없네요.","JPN":"ここにもシスターはいませんね。","ENG":"She's nowhere to be found.","TWN":"這裡也沒有修女呢。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"피 냄새는 계속해서 이어지고 있는데…….","JPN":"血の匂いはずっと続いてるのに……","ENG":"But the smell of blood keeps lingering...","TWN":"血腥味還在彌漫……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"어떡하면 좋을지 모르겠어요.","JPN":"ちょっと行き詰まりって感じです。","ENG":"I don't know what to do.","TWN":"我不知道該怎麼辦才好。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"돈이 걸린 문제가 아니라서 그런가?","JPN":"お金がかかった問題じゃないからかしら？","ENG":"Is it because there's no money on the line?","TWN":"因為不是涉及到錢的問題嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"멍멍이가 오늘따라 나를 많이 의지하는 것 같네?","JPN":"ワンちゃん、今日は私に頼りすぎてない？","ENG":"You're relying on me a lot more than usual today, Puppy.","TWN":"狗狗今天好像特別依賴我呢？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"언니는 학회의 종교학부장이잖아요.","JPN":"姉さんは学会の宗教学部長でしょう？","ENG":"You are the Society's Dean of Religion.","TWN":"姊姊是學會的宗教學院院長啊。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"적어도 저보다 아는 게 많을 테니 현명한 선택을 해주지 않을까요?","JPN":"少なくとも、私よりは多くを知っているでしょうから、賢明な判断をしてくれるんじゃないですか？","ENG":"You probably know more than I do, so I figured you'd make the smarter call.","TWN":"至少比我知道的多，應該會做出明智的選擇吧？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"이젠 홀로 서기를 시작해야지.","JPN":"もう独立しないと。","ENG":"It's time you started making decisions for yourself.","TWN":"現在該開始獨自面對了。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"둥지를 떠나는 아기 새를 바라보는 어미 새의 심정이 이랬을까?","JPN":"巣立つ雛鳥を見守る親鳥の気持ちってこんな感じなのかしらね。","ENG":"Is this what it feels like to watch a baby bird leave the nest?","TWN":"看著離巢的小鳥，母鳥的心情是不是也是這樣呢？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"끄응…….","JPN":"ぐぬぬ……","ENG":"Ngh...","TWN":"呃……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"후훗. 농담이야.","JPN":"ふふっ。冗談よ。","ENG":"Haha. I'm just kidding.","TWN":"嘿嘿，開個玩笑而已。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"우선 수녀를 찾아야 해요.","JPN":"まずはシスターを見つけないとですね。","ENG":"First, I need to find that nun.","TWN":"首先要找到修女。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"적어도 그 애는 뭔가를 알고 있는 눈치였어요.","JPN":"少なくともあの子は何かを知ってるようでした。","ENG":"She knows something. I can tell.","TWN":"至少她好像知道些什麼。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"어쩌면…… 그 애도 병이랑 관련 있을지도 모르겠네.","JPN":"もしかしたら……その子も病気と関係があるのかもしれないわね。","ENG":"Maybe... she knows something about the sickness.","TWN":"或許…… 那孩子也可能和病有關。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"맞아요. 제 말이 그 말이에요.","JPN":"そう。そのとおりです。","ENG":"Exactly! That's what I've been thinking.","TWN":"沒錯，就是這個意思。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"애초에 돈을 벌려는 목적이 그 병 때문이잖아요?","JPN":"そもそもお金を稼ぐ目的がその病気のためですから。","ENG":"I mean, earning money in the first place was all for that, wasn't it?","TWN":"本來就是為了賺錢治病，不是嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼 의뢰인이 눈치채기 전에 얼른 해결하는 게 좋겠어.","JPN":"じゃあ、依頼人が気付く前に早く解決した方が良さそうね。","ENG":"Then you'd better get it done before your client catches on.","TWN":"那最好在委託人察覺之前趕緊解決。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"네. 그럴려고요.","JPN":"はい。そのつもりです。","ENG":"Yeah, I plan to.","TWN":"嗯，是的。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아, 그리고 한 가지 물어볼 게 있는데요…….","JPN":"あ、それからもう1つ聞きたいんですけど……","ENG":"Oh, by the way, I wanted to ask you something...","TWN":"啊，還有一件事想問你……"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저…… 평소에 냄새가 많이 나나요?","JPN":"私……普段結構臭かったりします？","ENG":"Do I... smell?","TWN":"我……平時味道很重嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"누, 누린내라던가, 개털 냄새라던가…….","JPN":"け、獣臭とか、犬の匂いとか……","ENG":"Like, do I reek of sweat? Or smell like a wet dog?","TWN":"是，是發黴的味道，還是狗毛的味道……"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"푸훕…… 아, 미안. 너무 뜬금없어서.","JPN":"ぷっ……あ、ごめんね。あまりに唐突すぎて。","ENG":"Pfft... Oh, sorry. That was just so out of nowhere.","TWN":"噗哧……啊，抱歉。太突然了。"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"돈만 밝히는 속물로 자란 줄 알았는데.","JPN":"お金しか知らない俗物になったとばかり思っていたのに。","ENG":"And here I thought you grew up into a complete money-grubbing cynic.","TWN":"我以為你只是個唯利是圖的凡夫俗子。"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"제법 귀여운 면이 남아있었네, 우리 멍멍이?","JPN":"なかなか可愛い一面も残っていたのね、ワンちゃん。","ENG":"Guess there's still some cuteness left in you, Puppy.","TWN":"相當可愛呢，我的狗狗。"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L36_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아잇, 저는 진지하다니까요!","JPN":"もう、真剣なんですよ、私！","ENG":"Hey, I'm being serious!","TWN":"哎呀，我是認真的！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"수녀가 저한테 맛있는 냄새가 난다고 했어요.","JPN":"シスターが私から美味しそうな匂いがするって言ったんです。","ENG":"That nun said I smelled \\"delicious.\\"","TWN":"修女說我身上有好聞的味道。"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그 냄새가 침식체를 홀리고 있다고…….","JPN":"その匂いが侵食体を魅了してるって……","ENG":"Like, so good that it was attracting C.O.s.","TWN":"那個氣味正在吸引侵蝕體……"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저 깨끗이 씻고 다니잖아요. 그 수녀 코가 잘못된 거죠?","JPN":"私、いつも清潔にしてるじゃないですか。あのシスターの鼻が間違ってますよね？","ENG":"I bathe daily. There's no way it's me, right?!","TWN":"我可是洗得很乾淨的。一定是那個修女的鼻子有問題吧？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"후후…… 멍멍아.","JPN":"ふふ……ワンちゃん。","ENG":"Haha... Puppy.","TWN":"呵呵……狗狗。"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"정말인지 아닌지는 전부 확인해야 알 수 있는 법이야.","JPN":"本当かどうかは全部確認しないとわからないものだわ。","ENG":"You'll never know the truth unless you check for yourself.","TWN":"是真是假，只有確認過才能知道。"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"퇴마사라면, 진실을 보는 눈이 있어야 하지 않겠어?","JPN":"エクソシストなら、真実を見る目を持つべきよ。","ENG":"A true exorcist must have the eyes to see the truth.","TWN":"作為驅魔師，不應該有一雙看穿真相的眼睛嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"냄새나는지 안 나는지 대답이나 하라고!!","JPN":"臭いか臭くないか、聞いてるんですけど！！","ENG":"Just tell me if I smell or not!!","TWN":"快回答到底有沒有味道！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};